def find_deepest_nesting(paren_string):
    if not paren_string:
        return []
    groups = paren_string.split(' ')
    result = []
    for group in groups:
        count = 0
        max_count = 0
        for char in group:
            if char == '(':
                count += 1
                if count > max_count:
                    max_count = count
            elif char == ')':
                if count == 0:
                    raise ValueError("Unbalanced parentheses")
                count -= 1
            else:
                raise ValueError("Invalid character in parentheses string")
        if count != 0:
            raise ValueError("Unbalanced parentheses")
        result.append(max_count)
    return result

# Test cases
print(find_deepest_nesting("(()) (())"))  # Output: [2, 2]
print(find_deepest_nesting("((())) ()"))  # Output: [3, 1]
print(find_deepest_nesting(""))  # Output: []
print(find_deepest_nesting("()"))  # Output: [1]
print(find_deepest_nesting("((())())"))  # Output: [3]

# Edge cases
try:
    print(find_deepest_nesting(")("))  # Output: ValueError: Unbalanced parentheses
except ValueError as e:
