def rolling_max(numbers):
    if not numbers:
        return []
    max_nums = [numbers[0]]
    for i in range(1, len(numbers)):
        max_nums.append(max(max_nums[i-1], numbers[i]))
    return max_nums

def is_palindrome(string: str) -> bool:
    if len(string) == 0:
        return True
    else:
        return string == string[::-1]

def make_palindrome(string: str) -> str:
    if len(string) == 0:
        return ""
    elif len(string) == 1:
        return string
    else:
        for i in range(len(string)):
            if is_palindrome(string[i:]):
                return string + string[:i][::-1]

def string_xor(a: str, b: str) -> str:
    if len(a) != len(b):
        raise ValueError("Input strings should be of the same length")
    if not set(a).issubset(set('01')) or not set(b).issubset(set('01')):
        raise ValueError("Input strings should only contain 1s and 0s")
    return ''.join(str(int(x) ^ int(y)) for x, y in zip(a, b))

