def greatest_common_divisor(a: int, b: int) -> int:
    if a < 0 or b < 0:
        raise ValueError("Both a and b must be non-negative.")
    if a == 0 and b == 0:
        raise ValueError("Both a and b cannot be zero.")
    if a == 0:
        return b
    if b == 0:
        return a
    while b != 0:
        a, b = b, a % b
    return a

