def factorize(n):
    if n < 1:
        raise ValueError("Input number should be greater than 0.")
    factors = []
    for i in range(2, int(n**0.5) + 1):
        while n % i == 0:
            factors.append(i)
            n //= i
            if n == 1:
                return factors
    if n > 1:
        factors.append(n)
    return factors

def remove_duplicates(numbers):
    if not isinstance(numbers, list):
        raise TypeError("Input should be a list")
    if not all(isinstance(i, int) for i in numbers):
        raise TypeError("All elements in the list should be integers")

    counts = {}
    for num in numbers:
        if num in counts:
            counts[num] += 1
        else:
            counts[num] = 1

    return [num for num in numbers if counts[num] == 1]

