def is_prime(n):
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0 or n % 3 == 0:
        return False
    i = 5
    while i * i <= n:
        if n % i == 0 or n % (i + 2) == 0:
            return False
        i += 6
    return True

def prime_fib(n):
    if n < 1:
        return None
    fib_nums = [2, 3]
    i = 2
    while len(fib_nums) < n:
        fib_nums.append(fib_nums[i - 1] + fib_nums[i - 2])
        i += 1
    for num in fib_nums:
        if is_prime(num):
            n -= 1
            if n == 0:
                return num

def triples_sum_to_zero(l: list) -> bool:
    if len(l) < 3:
        return False
    l.sort()
    for i in range(len(l) - 2):
        if i > 0 and l[i] == l[i - 1]:
            continue
        left = i + 1
        right = len(l) - 1
        while left < right:
            current_sum = l[i] + l[left] + l[right]
            if current_sum < 0:
                left += 1
            elif current_sum > 0:
                right -= 1
            else:
                return True
    return False

