def circular_shift(x: int, shift: int) -> str:
    if x == 0:
        return "0"
    digits = list(str(x))
    if shift == 0:
        return str(x)
    if shift >= len(digits):
        return "".join(digits[::-1])
    else:
        return "".join(digits[-shift:] + digits[:-shift])

def fruit_distribution(s: str, n: int) -> int:
    if not s or n == 0:
        return 0
    apples, oranges = map(int, s.split()[::2])
    return n - apples - oranges

def pluck(arr: List[int]) -> List[int]:
    if not arr:
        return []
    even_numbers = [(i, num) for i, num in enumerate(arr) if num % 2 == 0]
    if not even_numbers:
        return []
    smallest_even = min(even_numbers, key=lambda x: x[1])
    return [smallest_even[1], smallest_even[0]]

from typing import List
from collections import Counter

def search(lst: List[int]) -> int:
    if not lst:
        return -1
    counter = Counter(lst)
    max_val = max(counter.keys())
    for i in range(max_val, 0, -1):
        if i in counter and counter[i] >= i:
            return i
    return -1

def strange_sort_list(lst: List[int]) -> List[int]:
    if len(lst) < 2:
        return lst
    else:
        mid = len(lst) // 2
        left = strange_sort_list(lst[:mid])
        right = strange_sort_list(lst[mid:])
        return merge(left, right)

def merge(left: List[int], right: List[int]) -> List[int]:
    merged = []
    while left and right:
        if left[0] < right[0]:
            merged.append(left.pop(0))
        else:
            merged.append(right.pop(0))
    merged.extend(left)
    merged.extend(right)
    return merged
