from typing import List

def smallest_change(arr: List[int]) -> int:
    if len(arr) == 0:
        return 0
    if len(arr) == 1:
        return 0
    if len(arr) == 2:
        return 0 if arr[0] == arr[1] else 1

    left = 0
    right = len(arr) - 1
    changes = 0

    while left <= right:
        if arr[left] != arr[right]:
            changes += 1
        left += 1
        right -= 1

    return changes

def total_match(lst1: List[str], lst2: List[str]) -> List[str]:
    if not lst1 and not lst2:
        return []
    total_chars1 = sum(len(s) for s in lst1)
    total_chars2 = sum(len(s) for s in lst2)
    if total_chars1 <= total_chars2:
        return lst1
    else:
        return lst2

def is_multiply_prime(a: int) -> bool:
    if a < 2:
        return False
    factors = []
    for i in range(2, a+1):
        if a % i == 0:
            factors.append(i)
            a //= i
            if a % i != 0:
                continue
            while a % i == 0:
                a //= i
    if len(factors) != 3:
        return False
    for factor in factors:
        for i in range(2, int(factor**0.5)+1):
            if factor % i == 0:
                return False
    return True

def is_simple_power(x: int, n: int) -> bool:
    if x <= 0 or n <= 0:
        return False
    if x == 1 or n == 1:
        return True
    if x == n:
        return True
    while x % n == 0:
        x = x // n
    return x == 1
