def check_dict_case(dict: dict) -> bool:
    if not dict:
        return False
    lower_case_keys = [key for key in dict.keys() if key.islower()]
    upper_case_keys = [key for key in dict.keys() if key.isupper()]
    return len(lower_case_keys) == len(dict) or len(upper_case_keys) == len(dict)

def count_up_to(n: int) -> list:
    if n <= 1:
        return []
    else:
        primes = []
        for possiblePrime in range(2, n):
            isPrime = True
            for num in range(2, possiblePrime):
                if possiblePrime % num == 0:
                    isPrime = False
            if isPrime:
                primes.append(possiblePrime)
        return primes

