def histogram(test: str) -> dict:
    if not test:
        return {}
    hist = {}
    for char in test:
        if char != ' ':
            hist[char] = hist.get(char, 0) + 1
    return hist

def reverse_delete(s: str, c: str) -> Tuple[str, bool]:
    if not s:
        return ("", False)
    if len(s) == 1:
        return ("", True)
    if s == s[::-1]:
        return (s, True)
    if len(set(s)) == 1:
        return ("", False)
    if not c:
        return (s, False)
    if len(c) == 1:
        s = s.replace(c, "")
        return (s, s == s[::-1])
    if set(c).issubset(set(s)):
        return ("", False)
    if set(c).isdisjoint(set(s)):
        return (s, False)
    for char in c:
        s = s.replace(char, "")
    return (s, s == s[::-1])

def minSubArraySum(nums: List[int]) -> int:
    if not nums:
        return 0

    min_sum = float('inf')
    current_sum = 0

    for num in nums:
        current_sum += num
        if current_sum < min_sum:
            min_sum = current_sum
        if current_sum > 0:
            current_sum = 0

    return min_sum if min_sum != float('inf') else max(nums)

def max_fill(grid: List[List[int]], capacity: int) -> int:
    if not grid or not grid[0]:
        return 0

    rows, cols = len(grid), len(grid[0])
    buckets = rows * cols // capacity
    remaining = sum(sum(row) for row in grid) % capacity

    return buckets + (1 if remaining > 0 else 0)

