def special_factorial(n: int) -> int:
    if n < 0:
        raise ValueError("Input must be a non-negative integer.")
    elif n == 0 or n == 1:
        return n
    else:
        factorial = 1
        for i in range(1, n + 1):
            factorial *= i
            while factorial % 10 == 0:
                factorial //= 10
            factorial %= 1000000007
        return factorial
