def even_odd_count(num: int) -> Tuple[int, int]:
    even_count = 0
    odd_count = 0
    if num == 0:
        return (1, 0)
    else:
        num = abs(num)
        while num > 0:
            digit = num % 10
            if digit % 2 == 0:
                even_count += 1
            else:
                odd_count += 1
            num = num // 10
        return (even_count, odd_count)

def right_angle_triangle(a: int, b: int, c: int) -> bool:
    # Check if the inputs are positive integers
    if not all(isinstance(i, int) and i > 0 for i in (a, b, c)):
        return False

    # Check if the inputs form a valid triangle
    if a + b <= c or a + c <= b or b + c <= a:
        return False

    # Check if the inputs form a right-angled triangle
    sides = sorted([a, b, c])
    return sides[0]**2 + sides[1]**2 == sides[2]**2

def find_max(words: List[str]) -> str:
    if not words:
        return ""
    max_unique_chars = 0
    max_word = ""
    for word in words:
        unique_chars = len(set(word))
        if unique_chars > max_unique_chars:
            max_unique_chars = unique_chars
            max_word = word
        elif unique_chars == max_unique_chars:
            max_word = min(max_word, word)
    return max_word

def eat(number: int, need: int, remaining: int) -> List[int]:
