def generate_integers(a: int, b: int) -> List[int]:
    # Check if a and b are integers
    if not isinstance(a, int) or not isinstance(b, int):
        raise ValueError("Both a and b must be integers.")

    # Check if a and b are positive
    if a <= 0 or b <= 0:
        raise ValueError("Both a and b must be positive.")

    # Check if a and b are equal
    if a == b:
        return []

    # Check if a is greater than b, if so swap their values
    if a > b:
        a, b = b, a

    # Generate the list of even integers between a and b
    return [i for i in range(a, b+1) if i % 2 == 0]
